const query = $input.first().json.query || {};
const jobId = (query.jobId || $input.first().json.jobId || '').trim();
if (!jobId) throw new Error('Missing required query parameter: jobId');
return [{ json: { jobId } }];

const jobId = $('Validate jobId').item.json.jobId;
const items = $input.all();

if (!items || items.length === 0 || !items[0].json || !items[0].json.id) {
  return [{
    json: {
      responseCode: 404,
      responseBody: JSON.stringify({ error: 'Job not found', jobId })
    }
  }];
}

const job = items[0].json;

const response = {
  jobId: job.id,
  status: job.status,
  repoName: job.repoName,
  repoUrl: job.repoUrl,
  owner: job.owner,
  createdAt: job.createdAt,
  updatedAt: job.updatedAt
};

if (job.status === 'COMPLETED' && job.analysisResult) {
  response.analysisResult = typeof job.analysisResult === 'string'
    ? JSON.parse(job.analysisResult)
    : job.analysisResult;
}

if (job.status === 'FAILED') {
  response.errorHint = 'Analysis failed. Verify the repo is accessible with the provided token and try again.';
  try {
    const ar = typeof job.analysisResult === 'string' ? JSON.parse(job.analysisResult) : job.analysisResult;
    if (ar && ar.insights) {
      const errInsight = ar.insights.find(i => i.type === 'error');
      if (errInsight) response.errorDetail = errInsight.text;
    }
  } catch(e) {}
}

return [{
  json: {
    responseCode: 200,
    responseBody: JSON.stringify(response)
  }
}];
